const fs = require('fs');
const path = require('path');

const root = path.resolve(__dirname, '..');
const registryPath = path.join(root, 'kubejs', 'data', 'gambit_kits.json');
const functionsRoot = path.join(root, 'GunFight', 'data', 'gun', 'functions');
const checkMode = process.argv.includes('--check');
const checkFailures = [];
const generatedHeader = [
  '# Generated by scripts/generate_gambit_functions.js from kubejs/data/gambit_kits.json.',
  '# Edit the registry and rerun the generator instead of hand-editing this file.',
  ''
];

function readRegistry() {
  const raw = JSON.parse(fs.readFileSync(registryPath, 'utf8'));
  const kits = Array.isArray(raw.kits) ? raw.kits : [];
  const seen = new Set();
  for (const kit of kits) {
    if (!kit || typeof kit.id !== 'string' || !/^[a-z0-9_]+$/.test(kit.id)) {
      throw new Error(`Invalid kit id: ${kit && kit.id}`);
    }
    if (seen.has(kit.id)) throw new Error(`Duplicate kit id: ${kit.id}`);
    seen.add(kit.id);
    if (!kit.display || !kit.color) throw new Error(`Kit ${kit.id} needs display and color`);
    const selector = kit.selector || {};
    for (const key of ['top', 'middle', 'bottom']) {
      if (!selector[key]) throw new Error(`Kit ${kit.id} selector is missing ${key}`);
    }
    const singlePath = path.join(functionsRoot, 'kits', 'single', `${kit.id}.mcfunction`);
    if (!fs.existsSync(singlePath)) throw new Error(`Missing kit loadout function: ${singlePath}`);
  }
  if (kits.length === 0) throw new Error('No kits found in registry');
  return kits;
}

function writeFunction(relativePath, lines) {
  const target = path.join(functionsRoot, relativePath);
  const content = `${lines.join('\n')}\n`;
  if (checkMode) {
    let current = null;
    try {
      current = fs.readFileSync(target, 'utf8');
    } catch (e) {
      checkFailures.push(`${relativePath} is missing`);
      return;
    }
    if (current !== content) checkFailures.push(`${relativePath} is out of date`);
    return;
  }
  fs.mkdirSync(path.dirname(target), { recursive: true });
  fs.writeFileSync(target, content, 'utf8');
}

function noKitTagSelector(kits) {
  return kits.map((kit) => `tag=!${kit.id}`).join(',');
}

function selectorPadCondition(kit) {
  const selector = kit.selector;
  return `if block ~ ~-1 ~ ${selector.top} if block ~ ~-2 ~ ${selector.middle} if block ~ ~-3 ~ ${selector.bottom}`;
}

function generateSelectorFunctions(kits) {
  for (const kit of kits) {
    writeFunction(`selectors/${kit.id}.mcfunction`, [
      ...generatedHeader,
      'function gun:selectors/clear_kits',
      `tag @s add ${kit.id}`,
      `title @s actionbar [{"text":"${kit.display} Kit Selected","color":"${kit.color}"}]`,
      'playsound minecraft:entity.item.pickup player @s ~ ~ ~ 0.6 1.2',
      'function gun:kits/clear_hotbar',
      `execute if entity @s[team=red] run function gun:kits/single/${kit.id}`,
      `execute if entity @s[team=blue] run function gun:kits/single/${kit.id}`,
      'execute if entity @s[team=red] run function gun:rations/give_random_self',
      'execute if entity @s[team=blue] run function gun:rations/give_random_self',
      'execute if entity @s[tag=in_range] run function gun:range/equip'
    ]);
  }
}

function generateKitTick(kits) {
  const lines = [
    ...generatedHeader,
    '# Kit selector tick - detect players standing on kit selection blocks',
    '# Lobby selection is always available for lobby players.'
  ];
  for (const kit of kits) {
    lines.push(`execute as @a[team=lobby,tag=!${kit.id},gamemode=adventure] at @s ${selectorPadCondition(kit)} run function gun:selectors/${kit.id}`);
  }
  lines.push('', '# TDM: allow pad selection directly for active Red/Blue players.');
  for (const team of ['Red', 'Blue']) {
    for (const kit of kits) {
      lines.push(`execute as @a[tag=${team},tag=!${kit.id},gamemode=adventure] at @s ${selectorPadCondition(kit)} run function gun:selectors/${kit.id}`);
    }
  }
  writeFunction('selectors/kit_tick.mcfunction', lines);
}

