function main() {
  const kits = readRegistry();
  generateSelectorFunctions(kits);
  generateKitTick(kits);
  generateLobbyTick(kits);
  generateEquipFunctions(kits);
  generateStartFunctions(kits);
  if (checkMode) {
    if (checkFailures.length > 0) {
      for (const failure of checkFailures) console.error(`Out of date: ${failure}`);
      process.exitCode = 1;
      return;
    }
    console.log(`Generated Gambit functions are up to date for ${kits.length} kits.`);
    return;
  }
  console.log(`Generated Gambit functions for ${kits.length} kits.`);
}

main();
